(function generateNextFormObject () {
    return new x_snc_nf.NextForm().addScreen().addRow().addColumn().addField(new x_snc_nf.NextField(
            'string',
            'Comment',
            'comment', {
                displayValue: '',
                value: '',
                displayValue: '',
		maxLength: 1000,
            fieldRegex: [{
                "pattern": '^[a-Z]*$',
                "placeholder": "",
                "guidanceText": "Value does not match required pattern",
                "type": "suggestion"
            }],
            nfValidation: {
                readonly: false,
                maxLength: 40,
                minLength: 10,
                mandatory: true,
                allowedValues: ['value 1', 'value 2']
            },
            }
        ));
})();
